const e=[{category:"압축기",category_en:"Compressor",title:"압축기가 기동하지 않는다",title_en:"Compressor does not start",causes:["전원 공급 불량 (차단기 트립, 퓨즈 단선)","과부하 릴레이 동작 (과전류)","기동 콘덴서 불량","압축기 내부 고착","고압 차단 스위치 동작"],causes_en:["Power supply failure (circuit breaker trip, fuse blown)","Overload relay activation (overcurrent)","Defective start capacitor","Internal compressor seizure","High pressure switch activation"],procedures:["1. 전원 전압 측정 - 정격 전압 ±10% 이내 확인","2. 차단기·퓨즈 상태 확인 및 복구","3. 과부하 릴레이 수동 리셋 후 재기동 시도","4. 기동 콘덴서 용량 측정 (정격 ±5% 이내)","5. 압축기 단자간 저항 측정 - 단선/지락 확인","6. 고압 스위치 차단 원인(냉매 과충전, 응축기 오염) 해결 후 리셋"],procedures_en:["1. Measure supply voltage - confirm within ±10% of rated voltage","2. Check and reset circuit breaker / fuse","3. Manually reset overload relay and attempt restart","4. Measure start capacitor capacity (within ±5% of rated value)","5. Measure resistance between compressor terminals - check for open/ground fault","6. Resolve high-pressure trip cause (overcharge, condenser fouling) then reset"],notes:"기동 실패 반복 시 압축기 권선 과열 우려 - 인터벌 두고 재시도",notes_en:"Repeated start failures risk winding overheat — allow cooling interval before retrying"},{category:"압축기",category_en:"Compressor",title:"압축기 과열 트립이 반복된다",title_en:"Compressor thermal trip repeats",causes:["흡입 압력 너무 낮음 (냉매 부족)","응축 압력 너무 높음 (응축기 오염)","냉동유 부족 또는 오염","흡입 필터 막힘","환경 온도 과도하게 높음"],causes_en:["Suction pressure too low (refrigerant shortage)","Condensing pressure too high (condenser fouling)","Insufficient or contaminated refrigeration oil","Suction filter clogged","Ambient temperature excessively high"],procedures:["1. 흡입 압력 및 토출 압력 측정","2. 냉매 충전량 확인 - 사이트글라스 기포 유무","3. 응축기 핀 상태 확인 및 세척","4. 흡입 스트레이너 청소 또는 교체","5. 냉동유 레벨 및 색상 확인","6. 기계실 환기 상태 점검"],procedures_en:["1. Measure suction and discharge pressures","2. Check refrigerant charge — inspect sight glass for bubbles","3. Check and clean condenser fins","4. Clean or replace suction strainer","5. Check oil level and color","6. Inspect machine room ventilation"],notes:"트립 후 최소 10분 냉각 후 재기동",notes_en:"Wait at least 10 minutes for cooling before restarting after trip"},{category:"냉각 불량",category_en:"Poor Cooling",title:"냉각 온도가 설정값에 도달하지 않는다",title_en:"Cooling temperature does not reach setpoint",causes:["냉매 부족 (누설)","팽창밸브 개도 불량","증발기 착상 과다","압축기 성능 저하","냉각 부하 과다"],causes_en:["Refrigerant shortage (leak)","Expansion valve opening malfunction","Excessive evaporator icing","Compressor performance degradation","Excessive cooling load"],procedures:["1. 흡입·토출 압력 측정으로 냉매량 확인","2. 증발기 착상 상태 육안 확인","3. 제상 히터·타이머 동작 확인","4. 팽창밸브 감온통 밀착 여부 확인","5. 냉매 누설 부위 탐지기 또는 비눗물로 점검","6. 압축기 흡입·토출 밸브 효율 확인"],procedures_en:["1. Measure suction/discharge pressure to assess refrigerant level","2. Visual inspection of evaporator icing","3. Check defrost heater and timer operation","4. Verify expansion valve sensing bulb contact","5. Check for refrigerant leaks using detector or soapy water","6. Assess compressor suction/discharge valve efficiency"],notes:"착상이 심한 경우 강제 제상 후 재측정",notes_en:"If heavy icing is present, force a defrost cycle before re-measuring"},{category:"냉각 불량",category_en:"Poor Cooling",title:"증발기에 서리(착상)가 과다하게 낀다",title_en:"Excessive frost buildup on evaporator",causes:["제상 히터 단선","제상 타이머·센서 불량","증발기 팬 모터 불량","도어 패킹 불량 (외부 습기 유입)","냉매 과충전 (저압 과도하게 낮음)"],causes_en:["Defrost heater open circuit","Defrost timer or sensor malfunction","Evaporator fan motor failure","Door gasket failure (moisture ingress)","Refrigerant overcharge (suction pressure too low)"],procedures:["1. 제상 타이머 동작 시간 확인","2. 제상 히터 저항 측정 (단선 확인)","3. 제상 종료 센서(온도 퓨즈) 도통 확인","4. 증발기 팬 모터 전류 및 회전 방향 확인","5. 도어 패킹 밀착 상태 육안 점검"],procedures_en:["1. Verify defrost timer cycle duration","2. Measure defrost heater resistance (check for open circuit)","3. Test defrost termination sensor (thermal fuse) continuity","4. Check evaporator fan motor current and rotation direction","5. Visually inspect door gasket seal"],notes:"강제 제상 모드로 진입해 히터 동작 전류 직접 측정 권장",notes_en:"Recommended: enter forced defrost mode and directly measure heater operating current"},{category:"소음/진동",category_en:"Noise / Vibration",title:"압축기에서 이상 소음이 난다",title_en:"Abnormal noise from compressor",causes:["액압축 (리퀴드백)","냉동유 부족","마운팅 볼트 이완","내부 밸브 파손","냉매 과충전"],causes_en:["Liquid slugging (liquid back)","Insufficient refrigeration oil","Loose mounting bolts","Internal valve damage","Refrigerant overcharge"],procedures:["1. 흡입관 온도 측정 - 과도한 과냉 여부 확인","2. 시동 시 소음인지 운전 중 소음인지 구분","3. 마운팅 볼트 조임 상태 확인","4. 냉동유 레벨 확인","5. 토출 온도 측정 - 정상보다 낮으면 액압축 의심"],procedures_en:["1. Measure suction line temperature — check for excessive subcooling","2. Determine if noise occurs at startup or during operation","3. Check tightness of mounting bolts","4. Check oil level","5. Measure discharge temperature — lower than normal suggests liquid slugging"],notes:"액압축은 압축기 파손으로 이어짐 - 즉시 운전 중단 후 원인 제거",notes_en:"Liquid slugging can destroy the compressor — stop operation immediately and eliminate the cause"},{category:"소음/진동",category_en:"Noise / Vibration",title:"실외기(응축기) 팬에서 소음이 난다",title_en:"Noise from condenser (outdoor unit) fan",causes:["팬 블레이드 이물질 접촉","베어링 마모","팬 블레이드 균열·변형","모터 고정 볼트 이완"],causes_en:["Foreign object contact with fan blade","Bearing wear","Fan blade crack or deformation","Loose motor mounting bolts"],procedures:["1. 전원 차단 후 팬 블레이드 이물질 제거","2. 블레이드 균열 및 변형 육안 확인","3. 모터 베어링 유격 확인 (손으로 흔들기)","4. 모터 고정 볼트 조임","5. 베어링 불량 시 모터 교체"],procedures_en:["1. Cut power and remove any foreign objects from fan blade","2. Visually inspect blade for cracks or deformation","3. Check motor bearing play (shake by hand)","4. Tighten motor mounting bolts","5. Replace motor if bearing is defective"],notes:"운전 중 소음 위치 특정 후 전원 차단",notes_en:"Identify noise location during operation, then cut power before inspection"},{category:"냉매",category_en:"Refrigerant",title:"냉매가 부족하다 (저압 낮음)",title_en:"Refrigerant shortage (low suction pressure)",causes:["누설 (플레어 이음부, 밸브 패킹, 용접부)","장기간 미점검으로 자연 감소","서비스 작업 후 충전 불충분"],causes_en:["Leak (flare joints, valve packing, weld points)","Natural reduction from long-term lack of inspection","Insufficient charge after service work"],procedures:["1. 저압 측 압력 측정 - 냉매별 정상 압력 확인","2. 전체 배관 누설 점검 (전자식 탐지기 또는 비눗물)","3. 누설 부위 수리 (플레어 재작업 또는 용접)","4. 진공 작업 후 규정량 충전","5. 충전 후 사이트글라스 기포 소멸 확인"],procedures_en:["1. Measure low-side pressure — confirm normal range for refrigerant type","2. Inspect all piping for leaks (electronic detector or soapy water)","3. Repair leak (re-flare or weld)","4. Evacuate system and recharge to specified amount","5. After charging, confirm bubbles disappear from sight glass"],notes:"누설 수리 없이 냉매만 추가 충전하지 않는다",notes_en:"Never add refrigerant without first repairing the leak"},{category:"전기",category_en:"Electrical",title:"차단기가 자꾸 내려간다 (트립)",title_en:"Circuit breaker keeps tripping",causes:["압축기 기동 전류 과다 (기동 콘덴서 불량)","누전 (배선 피복 손상, 압축기 권선 지락)","차단기 용량 부족 또는 노후","과부하 (냉매 과충전, 응축 압력 과고)"],causes_en:["Excessive compressor inrush current (defective start capacitor)","Ground fault (damaged wiring insulation, compressor winding ground)","Undersized or aged circuit breaker","Overload (refrigerant overcharge, high condensing pressure)"],procedures:["1. 차단기 종류 확인 (과전류 트립 vs 누전 트립)","2. 각 부하 분리 후 단독 기동 테스트로 원인 부하 특정","3. 압축기 권선 대지 절연저항 측정 (1MΩ 이상)","4. 기동 전류 측정 및 콘덴서 용량 확인","5. 차단기 정격 용량 적합성 확인"],procedures_en:["1. Identify breaker type (overcurrent trip vs. ground fault trip)","2. Isolate loads individually and test to pinpoint faulty load","3. Measure compressor winding insulation resistance to ground (≥1MΩ)","4. Measure inrush current and check capacitor capacity","5. Verify circuit breaker rated capacity is appropriate"],notes:"누전 차단기 동작 시 절연저항 측정 필수",notes_en:"Insulation resistance measurement is mandatory when an ELCB trips"},{category:"전기",category_en:"Electrical",title:"전자식 팽창밸브(EEV)가 제어되지 않는다",title_en:"Electronic expansion valve (EEV) not responding",causes:["EEV 드라이버 불량","EEV 코일 단선","제어 보드 신호 불량","온도 센서 불량 (과열도 감지 오류)"],causes_en:["EEV driver failure","EEV coil open circuit","Control board signal fault","Temperature sensor failure (superheat sensing error)"],procedures:["1. EEV 코일 저항 측정 (기종별 정격값 확인)","2. 드라이버 출력 신호 전압 측정","3. 흡입관 온도 센서 저항값 확인","4. 강제 수동 제어 모드로 EEV 동작 테스트","5. 코일 불량 시 교체 (단품 교체 가능 기종 많음)"],procedures_en:["1. Measure EEV coil resistance (compare to model-specific rated value)","2. Measure driver output signal voltage","3. Check suction temperature sensor resistance","4. Test EEV operation in forced manual control mode","5. Replace coil if defective (many models support coil-only replacement)"],notes:"EEV 완전 닫힘 고착 시 냉각 불량, 완전 열림 고착 시 액압축 발생",notes_en:"EEV stuck closed causes poor cooling; stuck open causes liquid slugging"},{category:"제어",category_en:"Control",title:"컨트롤러(보드) 오류 코드가 표시된다",title_en:"Controller (board) displays error code",causes:["센서 단선 또는 단락","보드 전원 불안정","통신 오류 (멀티형)","보드 자체 불량"],causes_en:["Sensor open or short circuit","Unstable board power supply","Communication error (multi-unit system)","Board failure"],procedures:["1. 오류 코드 기종별 매뉴얼로 원인 확인","2. 해당 센서 저항값 측정 (단선·단락 확인)","3. 보드 입력 전원 전압 확인","4. 커넥터 접촉 불량 확인 및 재삽입","5. 오류 코드 초기화 후 재발 여부 모니터링"],procedures_en:["1. Look up error code in model-specific manual","2. Measure associated sensor resistance (check open/short)","3. Check board input power voltage","4. Inspect connector contacts and reseat connectors","5. Reset error code and monitor for recurrence"],notes:"오류 코드 사진 촬영 후 초기화 - 재발 패턴 파악에 활용",notes_en:"Photograph the error code before resetting — useful for identifying recurrence patterns"}];export{e as symptoms};
